import type { Message, ContentPart } from "./memory";

/** Memory tier classification */
export type MemoryTier = 'working' | 'compressed' | 'reference';

/** Importance score for prioritization (0-100) */
export interface PriorityScore {
  importance: number;  // Semantic importance (goals, insights, decisions)
  recency: number;     // Temporal weight (recent = higher)
  relevance: number;   // Current context relevance
  composite: number;   // Weighted combination
}

/** Compressed representation of a message exchange */
export interface CompressedExchange {
  id: string;
  timestamp: string;
  tier: MemoryTier;
  summary: string;
  keywords: string[];
  priority: PriorityScore;
  originalTokenCount: number;
  compressedTokenCount: number;
  archiveRef?: string; // Path to full exchange in LTM
}

/** Memory compression configuration */
export interface CompressionConfig {
  workingMemoryTokens: number;    // Keep full fidelity for N tokens
  targetCompressionRatio: number; // Target (e.g., 0.3 = 70% reduction)
  priorityWeights: {
    importance: number;
    recency: number;
    relevance: number;
  };
  minPriorityThreshold: number;     // Don't compress above this score
}

