  workingMemoryTokens: 30000,  // Last 30K tokens at full fidelity
  targetCompressionRatio: 0.3, // Compress by 70%
  priorityWeights: {
    importance: 0.4,
    recency: 0.35,
    relevance: 0.25,
  },
  minPriorityThreshold: 75,     // Keep important messages uncompressed
};

